INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (1, 'Back Squat', 'Legs', 'Intermediate', 'Barbell, squat rack', '["Set the bar across your upper back and brace your core.","Sit the hips back and bend the knees under control.","Descend until thighs reach at least parallel.","Drive through the midfoot and stand tall."]', '["Knees collapsing inward","Losing core tension","Heels lifting off the floor"]', 4, '6-10', 'squat', 90, 'back-squat', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (2, 'Leg Press', 'Legs', 'Beginner', 'Leg press machine', '["Place feet shoulder-width on the platform.","Lower the sled until knees bend deeply without hips lifting.","Press the platform away while keeping knees aligned.","Stop just before locking the knees."]', '["Locking knees hard","Letting hips curl up","Using a shallow range of motion"]', 4, '10-15', 'press', 75, 'leg-press', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (3, 'Walking Lunges', 'Legs', 'Intermediate', 'Bodyweight or dumbbells', '["Stand tall with shoulders stacked over hips.","Step forward and lower both knees under control.","Push through the front foot to rise.","Alternate legs for the target reps."]', '["Short steps","Front knee caving inward","Torso leaning too far forward"]', 3, '10-12 each leg', 'lunge', 80, 'walking-lunges', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (4, 'Romanian Deadlift', 'Legs', 'Intermediate', 'Barbell or dumbbells', '["Hold the weight with soft knees and a tall chest.","Hinge the hips back while keeping the spine neutral.","Lower until hamstrings are stretched.","Drive hips forward to stand."]', '["Squatting instead of hinging","Rounding the back","Letting the bar drift forward"]', 3, '8-12', 'hinge', 85, 'romanian-deadlift', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (5, 'Calf Raises', 'Legs', 'Beginner', 'Machine, dumbbells, or step', '["Stand with feet hip-width apart.","Rise onto the balls of your feet.","Pause at the top and squeeze calves.","Lower slowly to a full stretch."]', '["Bouncing reps","Partial range","Rolling ankles outward"]', 4, '12-20', 'pulse', 40, 'calf-raises', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (6, 'Bench Press', 'Chest', 'Intermediate', 'Barbell, bench', '["Lie on the bench with shoulder blades squeezed.","Grip the bar slightly wider than shoulder width.","Lower the bar to the lower chest.","Press up and back until arms are extended."]', '["Flaring elbows too wide","Bouncing the bar","Feet moving around"]', 4, '5-8', 'press', 70, 'bench-press', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (7, 'Push-ups', 'Chest', 'Beginner', 'Bodyweight', '["Start in a plank with hands under shoulders.","Lower your chest toward the floor.","Keep body straight from head to heels.","Push the floor away to return to plank."]', '["Sagging hips","Half reps","Elbows flaring sharply"]', 3, '10-25', 'pushup', 50, 'push-ups', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (8, 'Incline Dumbbell Press', 'Chest', 'Intermediate', 'Incline bench, dumbbells', '["Set the bench to a moderate incline.","Start dumbbells beside the upper chest.","Press up while keeping wrists stacked.","Lower slowly with elbows under control."]', '["Bench set too steep","Dumbbells drifting forward","Shrugging shoulders"]', 3, '8-12', 'press', 65, 'incline-dumbbell-press', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (9, 'Cable Fly', 'Chest', 'Intermediate', 'Cable machine', '["Set pulleys around chest height.","Step forward with a slight lean.","Bring hands together in a wide arc.","Control the stretch on the way back."]', '["Turning it into a press","Overstretching shoulders","Rushing the eccentric"]', 3, '12-15', 'fly', 45, 'cable-fly', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (10, 'Dumbbell Pullover', 'Chest', 'Advanced', 'Bench, dumbbell', '["Lie across or along a bench with one dumbbell held above chest.","Lower the dumbbell behind your head with soft elbows.","Feel the chest and lats stretch.","Pull back to the starting position."]', '["Overarching lower back","Bending elbows too much","Going beyond shoulder comfort"]', 3, '10-12', 'arc', 45, 'dumbbell-pullover', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (11, 'Pull-ups', 'Back', 'Advanced', 'Pull-up bar', '["Hang from the bar with hands outside shoulder width.","Pull elbows down toward your ribs.","Raise your chin over the bar.","Lower to a controlled full hang."]', '["Kipping every rep","Stopping short at the bottom","Craning the neck"]', 4, '5-10', 'pull', 80, 'pull-ups', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (12, 'Lat Pulldown', 'Back', 'Beginner', 'Cable pulldown machine', '["Grip the bar wider than shoulder width.","Lean back slightly with chest lifted.","Pull the bar to upper chest.","Return slowly until arms are extended."]', '["Pulling behind the neck","Using momentum","Shrugging the shoulders"]', 3, '10-12', 'pull', 60, 'lat-pulldown', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (13, 'Barbell Row', 'Back', 'Intermediate', 'Barbell', '["Hinge forward with a neutral spine.","Let the bar hang below shoulders.","Row the bar toward the lower ribs.","Lower under control without standing up."]', '["Standing too upright","Jerking the weight","Rounding the back"]', 4, '6-10', 'row', 75, 'barbell-row', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (14, 'Seated Cable Row', 'Back', 'Beginner', 'Cable row machine', '["Sit tall with knees softly bent.","Pull the handle toward the lower ribs.","Squeeze shoulder blades together.","Reach forward under control."]', '["Rocking the torso","Shrugging","Letting the shoulders roll forward hard"]', 3, '10-14', 'row', 55, 'seated-cable-row', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (15, 'Face Pull', 'Back', 'Beginner', 'Cable rope', '["Set the rope around face height.","Pull the rope toward your eyebrows.","Keep elbows high and apart.","Return slowly with control."]', '["Pulling too low","Arching the back","Using too much weight"]', 3, '12-20', 'pull', 35, 'face-pull', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (16, 'Shoulder Press', 'Shoulders', 'Intermediate', 'Dumbbells or barbell', '["Start with weights at shoulder height.","Brace ribs down and squeeze glutes.","Press overhead until arms are extended.","Lower to shoulders with control."]', '["Overarching the lower back","Pressing forward","Bouncing from the shoulders"]', 4, '6-10', 'overhead', 65, 'shoulder-press', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (17, 'Lateral Raise', 'Shoulders', 'Beginner', 'Dumbbells or cables', '["Hold weights by your sides.","Raise arms out until elbows reach shoulder height.","Keep wrists neutral and elbows slightly bent.","Lower slowly."]', '["Swinging the torso","Raising too high","Leading with the hands instead of elbows"]', 4, '12-20', 'raise', 35, 'lateral-raise', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (18, 'Rear Delt Fly', 'Shoulders', 'Beginner', 'Dumbbells or reverse pec deck', '["Hinge forward or sit on the machine.","Open arms wide with soft elbows.","Squeeze rear shoulders at the top.","Return slowly."]', '["Using traps too much","Swinging","Rounding the spine"]', 3, '12-18', 'fly', 35, 'rear-delt-fly', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (19, 'Arnold Press', 'Shoulders', 'Advanced', 'Dumbbells', '["Start with dumbbells in front of shoulders, palms facing you.","Rotate palms outward as you press overhead.","Finish with biceps near ears.","Reverse the rotation while lowering."]', '["Going too heavy","Losing wrist control","Flaring ribs"]', 3, '8-12', 'overhead', 60, 'arnold-press', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (20, 'Dumbbell Curl', 'Biceps', 'Beginner', 'Dumbbells', '["Stand tall with dumbbells by your sides.","Curl weights up without moving elbows forward.","Squeeze biceps at the top.","Lower slowly to full extension."]', '["Swinging the hips","Elbows drifting forward","Dropping the weights"]', 3, '10-12', 'curl', 35, 'dumbbell-curl', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (21, 'Hammer Curl', 'Biceps', 'Beginner', 'Dumbbells', '["Hold dumbbells with palms facing each other.","Curl while keeping wrists neutral.","Pause near shoulder height.","Lower slowly."]', '["Turning wrists upward","Using momentum","Shortening the bottom range"]', 3, '10-14', 'curl', 35, 'hammer-curl', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (22, 'Cable Curl', 'Biceps', 'Beginner', 'Cable machine', '["Set the pulley low with a straight or EZ bar.","Keep elbows pinned near your ribs.","Curl the handle toward the chest.","Control the cable back down."]', '["Leaning back","Letting elbows flare","Using too much weight"]', 3, '12-15', 'curl', 30, 'cable-curl', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (23, 'Preacher Curl', 'Biceps', 'Intermediate', 'Preacher bench, EZ bar', '["Rest upper arms on the preacher pad.","Lower the bar until elbows are almost straight.","Curl up without lifting arms from the pad.","Squeeze and repeat."]', '["Bouncing at the bottom","Lifting elbows","Short reps"]', 3, '8-12', 'curl', 35, 'preacher-curl', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (24, 'Triceps Pushdown', 'Triceps', 'Beginner', 'Cable machine, rope or bar', '["Set the cable high and hold the attachment.","Pin elbows to your sides.","Extend elbows until arms are straight.","Return with control without moving upper arms."]', '["Elbows drifting forward","Leaning over the stack","Partial lockout"]', 3, '10-15', 'pushdown', 35, 'triceps-pushdown', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (25, 'Dips', 'Triceps', 'Advanced', 'Parallel bars or assisted dip machine', '["Support yourself with arms straight.","Lower until elbows bend deeply.","Keep shoulders controlled and chest proud.","Press back to the top."]', '["Shoulders shrugging","Dropping too deep too fast","Half reps"]', 3, '6-12', 'dip', 60, 'dips', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (26, 'Overhead Triceps Extension', 'Triceps', 'Intermediate', 'Dumbbell or cable', '["Hold the weight overhead with elbows pointing forward.","Lower behind the head by bending elbows.","Keep upper arms mostly still.","Extend back overhead."]', '["Elbows flaring wide","Arching the back","Cutting the stretch short"]', 3, '10-14', 'overhead', 40, 'overhead-triceps-extension', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (27, 'Skull Crusher', 'Triceps', 'Intermediate', 'EZ bar or dumbbells', '["Lie on a bench with weight above shoulders.","Bend elbows and lower weight toward forehead.","Keep upper arms angled steady.","Extend elbows to return."]', '["Moving shoulders too much","Flaring elbows","Lowering too fast"]', 3, '8-12', 'pushdown', 40, 'skull-crusher', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (28, 'Plank', 'Abs', 'Beginner', 'Bodyweight', '["Set elbows under shoulders.","Keep body straight from head to heels.","Brace abs and squeeze glutes.","Hold for the target time."]', '["Hips sagging","Holding breath","Head dropping"]', 3, '30-60 seconds', 'brace', 30, 'plank', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (29, 'Crunches', 'Abs', 'Beginner', 'Bodyweight or mat', '["Lie on your back with knees bent.","Curl ribs toward hips.","Pause briefly at the top.","Lower shoulders back to the mat."]', '["Pulling the neck","Using momentum","Flattening reps into sit-ups"]', 3, '15-25', 'crunch', 35, 'crunches', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (30, 'Hanging Leg Raises', 'Abs', 'Advanced', 'Pull-up bar or captain''s chair', '["Hang with shoulders active.","Lift legs while curling pelvis upward.","Pause without swinging.","Lower slowly to a dead stop."]', '["Swinging","Only using hip flexors","Dropping legs fast"]', 3, '8-15', 'raise', 50, 'hanging-leg-raises', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (31, 'Russian Twists', 'Abs', 'Intermediate', 'Bodyweight, plate, or medicine ball', '["Sit with torso leaned back and core braced.","Rotate ribs side to side.","Tap the floor lightly beside each hip.","Keep movement controlled."]', '["Only moving the arms","Rounding the back","Racing through reps"]', 3, '20-30 total', 'twist', 40, 'russian-twists', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (32, 'Treadmill Intervals', 'Cardio', 'Intermediate', 'Treadmill', '["Warm up for five minutes.","Alternate hard running with easy recovery.","Keep posture tall and cadence quick.","Cool down before stopping."]', '["Skipping warm-up","Starting too fast","Holding the rails"]', 8, '30 sec hard / 60 sec easy', 'run', 180, 'treadmill-intervals', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (33, 'Rowing Machine', 'Cardio', 'Beginner', 'Rower', '["Push with legs first.","Open the hips after the leg drive.","Pull handle toward lower ribs.","Recover arms, body, then legs."]', '["Pulling with arms first","Rounding the back","Rushing the recovery"]', 1, '10-20 minutes', 'row', 160, 'rowing-machine', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (34, 'Battle Ropes', 'Cardio', 'Intermediate', 'Battle ropes', '["Set an athletic stance with knees bent.","Brace the core and keep chest tall.","Drive alternating waves through the ropes.","Maintain pace for the interval."]', '["Standing upright","Only using arms","Letting waves die early"]', 6, '20-30 seconds', 'wave', 120, 'battle-ropes', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (35, 'Burpees', 'Full Body', 'Intermediate', 'Bodyweight', '["Drop hands to the floor.","Jump or step feet back to plank.","Return feet under hips.","Stand or jump tall."]', '["Sagging in plank","Landing stiff-legged","Losing breathing rhythm"]', 4, '8-15', 'burpee', 110, 'burpees', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (36, 'Kettlebell Swing', 'Full Body', 'Intermediate', 'Kettlebell', '["Hike the kettlebell between the legs.","Snap hips forward powerfully.","Let the bell float to chest height.","Guide it back into the next hinge."]', '["Squatting the swing","Lifting with shoulders","Overextending the lower back"]', 4, '12-20', 'hinge', 120, 'kettlebell-swing', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (37, 'Clean and Press', 'Full Body', 'Advanced', 'Barbell or dumbbells', '["Pull the weight from the floor with a strong leg drive.","Catch it at the shoulders.","Brace and press overhead.","Lower safely back to the start."]', '["Muscling the clean","Loose core overhead","Poor catch position"]', 4, '3-6', 'overhead', 130, 'clean-and-press', NULL, NULL, NULL);
INSERT INTO "exercises" ("id", "name", "muscle_group", "difficulty", "equipment", "instructions", "common_mistakes", "recommended_sets", "recommended_reps", "animation_type", "calories_estimate", "animation_asset_key", "animation_media_type", "animation_src", "animation_credit") VALUES (38, 'Medicine Ball Slams', 'Full Body', 'Beginner', 'Medicine ball', '["Raise the ball overhead.","Brace and slam it to the floor.","Squat to retrieve the ball.","Repeat with full-body rhythm."]', '["Only using arms","Rounding to pick up","Throwing without control"]', 4, '10-15', 'slam', 95, 'medicine-ball-slams', NULL, NULL, NULL);
